            $WarningWindowDays
        } elseif ($null -ne $config.warningWindowDays) {
            [int]$config.warningWindowDays
        } else {
            30
        }

        $effectiveAsOf = if ($PSBoundParameters.ContainsKey('AsOf')) {
            $AsOf
        } elseif ($config.asOf) {
            [DateTime]$config.asOf
        } else {
            Get-Date
        }

