            $output = Format-RotationReportJson -Report $report
        } else {
            $output = Format-RotationReportMarkdown -Report $report
        }

        # Always print human-readable markers for CI verification
        Write-Output "ROTATION_VALIDATOR_SUMMARY: expired=$($report.summary.expired) warning=$($report.summary.warning) ok=$($report.summary.ok)"

        # Derive fixture name from the config file basename for unique markers
        $fixtureName = [System.IO.Path]::GetFileNameWithoutExtension($ConfigFile)
        Write-Output "FIXTURE_${fixtureName}_EXPIRED=$($report.summary.expired)"
        Write-Output "FIXTURE_${fixtureName}_WARNING=$($report.summary.warning)"
        Write-Output "FIXTURE_${fixtureName}_OK=$($report.summary.ok)"

        # Print the full report
        Write-Output $output
    }
    catch {
        Write-Error "Secret rotation validator failed: $($_.Exception.Message)"
        exit 1
    }
}

# Invoke-SecretRotationValidator.ps1
# Secret rotation validator: loads secret metadata, classifies by urgency,
# and generates reports in markdown or JSON format.
#
# TDD Implementation: functions written to make failing Pester tests pass.
# Run tests with: Invoke-Pester -Path ./SecretRotationValidator.Tests.ps1

[CmdletBinding()]
param(
    # Path to a JSON file containing secrets configuration
    [string]$ConfigFile,

    # How many days before expiry to warn (default 30)
    [int]$WarningWindowDays = 30,

    # Output format: 'markdown' or 'json'
    [ValidateSet("markdown", "json")]
    [string]$OutputFormat = "markdown",

    # Optional: treat this date as "today" for deterministic testing
    [DateTime]$AsOf
)

# ============================================================
# TDD Round 1 Implementation: Get-SecretDaysUntilExpiry
# Calculates how many days remain before a secret must be rotated.
# Negative value = already expired.
# ============================================================
function Get-SecretDaysUntilExpiry {
    param(
        [Parameter(Mandatory)]
        [DateTime]$LastRotated,

        [Parameter(Mandatory)]
        [int]$RotationPolicyDays,

        # Allow callers to override "today" for deterministic testing.
        # Use Nullable to avoid parameter set conflicts when called without -AsOf.
        [Nullable[DateTime]]$AsOf = $null
    )

    # Default to today when not specified (supports deterministic testing via override)
    $effectiveAsOf = if ($null -eq $AsOf) { (Get-Date).Date } else { $AsOf.Date }
    $expiryDate = $LastRotated.AddDays($RotationPolicyDays)
    return [int]($expiryDate - $effectiveAsOf).TotalDays
}

# ============================================================
# TDD Round 2 Implementation: Get-SecretUrgency
# Classifies a secret as 'expired', 'warning', or 'ok'.
# ============================================================
function Get-SecretUrgency {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [int]$DaysUntilExpiry,

        # Warn when this many days or fewer remain before expiry
        [int]$WarningWindowDays = 30
    )

    if ($DaysUntilExpiry -le 0) {
        return "expired"
    }
    elseif ($DaysUntilExpiry -le $WarningWindowDays) {
        return "warning"
    }
    else {
        return "ok"
    }
}

# ============================================================
# TDD Round 3 Implementation: Get-SecretRotationReport
# Builds the full rotation report, grouping secrets by urgency.
# ============================================================
function Get-SecretRotationReport {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [array]$Secrets,

        [int]$WarningWindowDays = 30,

        [DateTime]$AsOf = (Get-Date)
    )

    $expired = [System.Collections.Generic.List[PSObject]]::new()
    $warning = [System.Collections.Generic.List[PSObject]]::new()
    $ok      = [System.Collections.Generic.List[PSObject]]::new()

    foreach ($secret in $Secrets) {
        $days    = Get-SecretDaysUntilExpiry `
            -LastRotated $secret.LastRotated `
            -RotationPolicyDays $secret.RotationPolicyDays `
            -AsOf $AsOf
        $urgency = Get-SecretUrgency -DaysUntilExpiry $days -WarningWindowDays $WarningWindowDays

        # Enrich secret object with computed fields
        $enriched = [PSCustomObject]@{
            Name               = $secret.Name
            LastRotated        = $secret.LastRotated
            RotationPolicyDays = $secret.RotationPolicyDays
            DaysUntilExpiry    = $days
            RequiredByServices = $secret.RequiredByServices
            Urgency            = $urgency
        }

        switch ($urgency) {
            "expired" { $expired.Add($enriched) }
            "warning" { $warning.Add($enriched) }
            "ok"      { $ok.Add($enriched) }
        }
    }

    return [PSCustomObject]@{
        expired = $expired.ToArray()
        warning = $warning.ToArray()
        ok      = $ok.ToArray()
        summary = [PSCustomObject]@{
            expired = $expired.Count
            warning = $warning.Count
            ok      = $ok.Count
        }
        generatedAt       = (Get-Date -Format "yyyy-MM-ddTHH:mm:ss")
        warningWindowDays = $WarningWindowDays
    }
}

