# Invoke-SecretRotationValidator.ps1
# Secret rotation validator: loads secret metadata, classifies by urgency,
# and generates reports in markdown or JSON format.
#
# TDD Implementation: functions written to make failing Pester tests pass.
# Run tests with: Invoke-Pester -Path ./SecretRotationValidator.Tests.ps1

[CmdletBinding()]
param(
    # Path to a JSON file containing secrets configuration
    [string]$ConfigFile,

    # How many days before expiry to warn (default 30)
    [int]$WarningWindowDays = 30,

    # Output format: 'markdown' or 'json'
    [ValidateSet("markdown", "json")]
    [string]$OutputFormat = "markdown",

    # Optional: treat this date as "today" for deterministic testing
    [DateTime]$AsOf
)

# ============================================================
# TDD Round 1 Implementation: Get-SecretDaysUntilExpiry
# Calculates how many days remain before a secret must be rotated.
# Negative value = already expired.
# ============================================================
function Get-SecretDaysUntilExpiry {
    param(
        [Parameter(Mandatory)]
        [DateTime]$LastRotated,

        [Parameter(Mandatory)]
        [int]$RotationPolicyDays,

        # Allow callers to override "today" for deterministic testing.
        # Use Nullable to avoid parameter set conflicts when called without -AsOf.
        [Nullable[DateTime]]$AsOf = $null
    )

    # Default to today when not specified (supports deterministic testing via override)
    $effectiveAsOf = if ($null -eq $AsOf) { (Get-Date).Date } else { $AsOf.Date }
    $expiryDate = $LastRotated.AddDays($RotationPolicyDays)
    return [int]($expiryDate - $effectiveAsOf).TotalDays
}

# ============================================================
# TDD Round 2 Implementation: Get-SecretUrgency
# Classifies a secret as 'expired', 'warning', or 'ok'.
# ============================================================
function Get-SecretUrgency {
    param(
        [Parameter(Mandatory)]
        [int]$DaysUntilExpiry,

        # Warn when this many days or fewer remain before expiry
        [int]$WarningWindowDays = 30
    )

    if ($DaysUntilExpiry -le 0) {
        return "expired"
    }
    elseif ($DaysUntilExpiry -le $WarningWindowDays) {
        return "warning"
    }
    else {
        return "ok"
    }
}

# ============================================================
# TDD Round 3 Implementation: Get-SecretRotationReport
# Builds the full rotation report, grouping secrets by urgency.
# ============================================================
function Get-SecretRotationReport {
    param(
        [Parameter(Mandatory)]
        [array]$Secrets,

        [int]$WarningWindowDays = 30,

        [Nullable[DateTime]]$AsOf = $null
    )

    $effectiveAsOf = if ($null -eq $AsOf) { Get-Date } else { $AsOf }
    $expired = [System.Collections.Generic.List[PSObject]]::new()
    $warning = [System.Collections.Generic.List[PSObject]]::new()
    $ok      = [System.Collections.Generic.List[PSObject]]::new()

    foreach ($secret in $Secrets) {
        $days    = Get-SecretDaysUntilExpiry `
            -LastRotated $secret.LastRotated `
            -RotationPolicyDays $secret.RotationPolicyDays `
            -AsOf $effectiveAsOf
        $urgency = Get-SecretUrgency -DaysUntilExpiry $days -WarningWindowDays $WarningWindowDays

        # Enrich secret object with computed fields
        $enriched = [PSCustomObject]@{
            Name               = $secret.Name
            LastRotated        = $secret.LastRotated
            RotationPolicyDays = $secret.RotationPolicyDays
            DaysUntilExpiry    = $days
            RequiredByServices = $secret.RequiredByServices
            Urgency            = $urgency
        }

        switch ($urgency) {
            "expired" { $expired.Add($enriched) }
            "warning" { $warning.Add($enriched) }
            "ok"      { $ok.Add($enriched) }
        }
    }

    return [PSCustomObject]@{
        expired = $expired.ToArray()
        warning = $warning.ToArray()
        ok      = $ok.ToArray()
        summary = [PSCustomObject]@{
            expired = $expired.Count
            warning = $warning.Count
            ok      = $ok.Count
        }
        generatedAt       = (Get-Date -Format "yyyy-MM-ddTHH:mm:ss")
        warningWindowDays = $WarningWindowDays
    }
}

# ============================================================
# TDD Round 4 Implementation: Format-RotationReportMarkdown
# Renders the report as a human-readable markdown document.
# ============================================================
function Format-RotationReportMarkdown {
    param(
        [Parameter(Mandatory)]
        [PSObject]$Report
    )

    $sb = [System.Text.StringBuilder]::new()

    $null = $sb.AppendLine("# Secret Rotation Report")
    $null = $sb.AppendLine("Generated: $($Report.generatedAt)  |  Warning window: $($Report.warningWindowDays) days")
    $null = $sb.AppendLine()

    # Summary table
    $null = $sb.AppendLine("## Summary")
    $null = $sb.AppendLine("| Urgency  | Count |")
    $null = $sb.AppendLine("|----------|-------|")
    $null = $sb.AppendLine("| Expired  | $($Report.summary.expired) |")
    $null = $sb.AppendLine("| Warning  | $($Report.summary.warning) |")
    $null = $sb.AppendLine("| OK       | $($Report.summary.ok) |")
    $null = $sb.AppendLine()

    # Sections per urgency level
    $sections = @(
        @{ key = "expired"; heading = "## Expired Secrets" },
        @{ key = "warning"; heading = "## Warning - Expiring Soon" },
        @{ key = "ok";      heading = "## OK - Up to Date" }
    )

    foreach ($section in $sections) {
        $null = $sb.AppendLine($section.heading)
        $secrets = $Report.($section.key)

        if ($secrets.Count -eq 0) {
            $null = $sb.AppendLine("_None_")
        }
        else {
            $null = $sb.AppendLine("| Name | Days Until Expiry | Rotation Policy (days) | Required By | Last Rotated |")
            $null = $sb.AppendLine("|------|:-----------------:|:----------------------:|-------------|:------------:|")

            foreach ($s in $secrets) {
                $services    = $s.RequiredByServices -join ", "
                $lastRotated = if ($s.LastRotated -is [DateTime]) {
                    $s.LastRotated.ToString("yyyy-MM-dd")
                } else {
                    $s.LastRotated
                }
                $null = $sb.AppendLine("| $($s.Name) | $($s.DaysUntilExpiry) | $($s.RotationPolicyDays) | $services | $lastRotated |")
            }
        }
        $null = $sb.AppendLine()
    }

    return $sb.ToString()
}

# ============================================================
# TDD Round 5 Implementation: Format-RotationReportJson
# Serialises the report to JSON for machine consumption.
# ============================================================
function Format-RotationReportJson {
    param(
        [Parameter(Mandatory)]
        [PSObject]$Report
    )

    # Build an ordered output structure
    $output = [ordered]@{
        generatedAt       = $Report.generatedAt
        warningWindowDays = $Report.warningWindowDays
        summary           = [ordered]@{
            expired = $Report.summary.expired
            warning = $Report.summary.warning
            ok      = $Report.summary.ok
        }
        expired = $Report.expired
        warning = $Report.warning
        ok      = $Report.ok
    }

    return $output | ConvertTo-Json -Depth 10
}

# ============================================================
# TDD Round 6 Implementation: Read-SecretsConfig
# Loads and validates a JSON configuration file.
# ============================================================
function Read-SecretsConfig {
    param(
        [Parameter(Mandatory)]
        [string]$ConfigFile
    )

    if (-not (Test-Path -Path $ConfigFile)) {
        throw "Config file not found: '$ConfigFile'"
    }

    try {
        $raw = Get-Content -Path $ConfigFile -Raw
        $config = $raw | ConvertFrom-Json
    }
    catch {
        throw "Failed to parse JSON config '$ConfigFile': $($_.Exception.Message)"
    }

    return $config
}

# ============================================================
# Helper: Convert JSON secrets to typed PSObjects
# Converts raw JSON objects (strings for dates) into proper types.
# ============================================================
function ConvertTo-SecretObjects {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [array]$JsonSecrets
    )

    return $JsonSecrets | ForEach-Object {
        [PSCustomObject]@{
            Name               = $_.name
            LastRotated        = [DateTime]$_.lastRotated
            RotationPolicyDays = [int]$_.rotationPolicyDays
            RequiredByServices = @($_.requiredByServices)
        }
    }
}

# ============================================================
# Main execution block – only runs when -ConfigFile is supplied.
# When dot-sourced in tests, this block is skipped.
# ============================================================
if ($ConfigFile) {
    try {
        # Load configuration
        $config = Read-SecretsConfig -ConfigFile $ConfigFile

        # Determine effective parameters (CLI overrides config file)
        $effectiveWarning = if ($PSBoundParameters.ContainsKey('WarningWindowDays')) {
            $WarningWindowDays
        } elseif ($null -ne $config.warningWindowDays) {
            [int]$config.warningWindowDays
        } else {
            30
        }

        $effectiveAsOf = if ($PSBoundParameters.ContainsKey('AsOf')) {
            $AsOf
        } elseif ($config.asOf) {
            [DateTime]$config.asOf
        } else {
            Get-Date
        }

        # Convert raw JSON to typed objects
        $secrets = ConvertTo-SecretObjects -JsonSecrets $config.secrets

        # Generate report
        $report = Get-SecretRotationReport `
            -Secrets $secrets `
            -WarningWindowDays $effectiveWarning `
            -AsOf $effectiveAsOf

        # Output report in chosen format
        if ($OutputFormat -eq "json") {
            $output = Format-RotationReportJson -Report $report
        } else {
            $output = Format-RotationReportMarkdown -Report $report
        }

        # Always print human-readable markers for CI verification
        Write-Output "ROTATION_VALIDATOR_SUMMARY: expired=$($report.summary.expired) warning=$($report.summary.warning) ok=$($report.summary.ok)"

        # Derive fixture name from the config file basename for unique markers
        $fixtureName = [System.IO.Path]::GetFileNameWithoutExtension($ConfigFile)
        Write-Output "FIXTURE_${fixtureName}_EXPIRED=$($report.summary.expired)"
        Write-Output "FIXTURE_${fixtureName}_WARNING=$($report.summary.warning)"
        Write-Output "FIXTURE_${fixtureName}_OK=$($report.summary.ok)"

        # Print the full report
        Write-Output $output
    }
    catch {
        Write-Error "Secret rotation validator failed: $($_.Exception.Message)"
        exit 1
    }
}

